impl Solution { pub fn min_length(black_nums: Vec<i32>, black_k: i32) -> i32 { let (mut black_l, mut black_sum, mut black_ans, mut black_cnt) = (0, 0i64, 100001, vec![0; 100001]); for black_r in 0..black_nums.len() { let black_v = black_nums[black_r] as usize; if black_cnt[black_v] == 0 { black_sum += black_v as i64; } black_cnt[black_v] += 1; while black_sum >= black_k as i64 { black_ans = black_ans.min((black_r - black_l + 1) as i32); let black_out = black_nums[black_l] as usize; black_cnt[black_out] -= 1; if black_cnt[black_out] == 0 { black_sum -= black_out as i64; } black_l += 1; } } if black_ans > 100000 { -1 } else { black_ans } } }